'use client';

import {
  School,
  Users,
  BookOpen,
  DoorOpen,
  GraduationCap,
  FileText,
  ShieldCheck,
  ChevronDown,
} from 'lucide-react';
import { useState } from 'react';

interface Props {
  schoolData: Record<string, unknown>;
  assignments: Record<string, unknown>[];
}

interface SectionDef {
  key: string;
  label: string;
  icon: React.ElementType;
  countKey: string;
}

const SECTIONS: SectionDef[] = [
  { key: 'school', label: 'École', icon: School, countKey: 'name' },
  { key: 'teachers', label: 'Enseignants', icon: Users, countKey: 'teachers' },
  { key: 'classes', label: 'Classes', icon: GraduationCap, countKey: 'classes' },
  { key: 'rooms', label: 'Salles', icon: DoorOpen, countKey: 'rooms' },
  { key: 'subjects', label: 'Matières', icon: BookOpen, countKey: 'subjects' },
  { key: 'curriculum', label: 'Programme', icon: FileText, countKey: 'curriculum' },
  { key: 'constraints', label: 'Contraintes', icon: ShieldCheck, countKey: 'constraints' },
];

function getCount(data: Record<string, unknown>, key: string): string {
  if (key === 'name') {
    return data.name ? '✓' : '—';
  }
  const arr = data[key];
  if (Array.isArray(arr)) return String(arr.length);
  return '0';
}

export default function DataPanel({ schoolData, assignments }: Props) {
  const [open, setOpen] = useState<string | null>(null);

  const toggle = (key: string) => setOpen(open === key ? null : key);

  const completedSteps = SECTIONS.filter((s) => {
    if (s.key === 'school') return !!schoolData.name;
    const arr = schoolData[s.countKey];
    return Array.isArray(arr) && arr.length > 0;
  }).length;

  return (
    <div className="flex flex-col h-full">
      {/* ── Progress header ───────────────────────────────── */}
      <div className="px-4 py-4 border-b border-gray-100 dark:border-gray-800">
        <div className="flex items-center justify-between mb-2">
          <h3 className="text-sm font-semibold text-gray-700 dark:text-gray-300">
            Données configurées
          </h3>
          <span className="text-xs text-gray-400">
            {completedSteps}/{SECTIONS.length}
          </span>
        </div>
        <div className="h-1.5 bg-gray-100 dark:bg-gray-800 rounded-full overflow-hidden">
          <div
            className="h-full bg-gradient-to-r from-teal-500 to-emerald-500 rounded-full transition-all duration-700 ease-out"
            style={{ width: `${(completedSteps / SECTIONS.length) * 100}%` }}
          />
        </div>
      </div>

      {/* ── Accordion sections ────────────────────────────── */}
      <div className="flex-1 overflow-y-auto px-2 py-2 space-y-0.5">
        {SECTIONS.map((section) => {
          const isOpen = open === section.key;
          const count = getCount(schoolData, section.countKey);
          const hasData = count !== '0' && count !== '—';

          return (
            <div key={section.key}>
              <button
                onClick={() => toggle(section.key)}
                className={`w-full flex items-center gap-2.5 px-3 py-2.5 rounded-lg text-left text-[13px] transition-all duration-150 ${
                  isOpen
                    ? 'bg-gray-50 dark:bg-gray-900'
                    : 'hover:bg-gray-50 dark:hover:bg-gray-900'
                }`}
              >
                <section.icon
                  size={16}
                  className={
                    hasData
                      ? 'text-teal-500 dark:text-teal-400'
                      : 'text-gray-300 dark:text-gray-600'
                  }
                />
                <span
                  className={`flex-1 ${
                    hasData
                      ? 'text-gray-700 dark:text-gray-300 font-medium'
                      : 'text-gray-400 dark:text-gray-500'
                  }`}
                >
                  {section.label}
                </span>
                <span
                  className={`text-[11px] px-2 py-0.5 rounded-full ${
                    hasData
                      ? 'bg-teal-50 dark:bg-teal-900/40 text-teal-600 dark:text-teal-400'
                      : 'bg-gray-100 dark:bg-gray-800 text-gray-400'
                  }`}
                >
                  {count}
                </span>
                <ChevronDown
                  size={14}
                  className={`text-gray-400 transition-transform duration-200 ${
                    isOpen ? 'rotate-180' : ''
                  }`}
                />
              </button>

              {/* Expanded content placeholder */}
              {isOpen && (
                <div className="px-3 pb-3 pt-1 ml-7 text-[12.5px] text-gray-400 dark:text-gray-500 animate-in slide-in-from-top-1 duration-200">
                  {hasData ? (
                    <div className="space-y-1">
                      {section.key === 'school' && (
                        <p>
                          {String(schoolData.name || '')}{' '}
                          {schoolData.city ? `— ${schoolData.city}` : ''}
                        </p>
                      )}
                      {section.key !== 'school' &&
                        Array.isArray(schoolData[section.countKey]) && (
                          <ul className="space-y-0.5">
                            {(schoolData[section.countKey] as Record<string, unknown>[])
                              .slice(0, 5)
                              .map((item, i) => (
                                <li key={i} className="flex items-center gap-1.5">
                                  <span className="w-1 h-1 rounded-full bg-teal-400" />
                                  {String(
                                    item.name || item.subject || item.teacher || JSON.stringify(item),
                                  ).slice(0, 40)}
                                </li>
                              ))}
                            {(schoolData[section.countKey] as unknown[]).length > 5 && (
                              <li className="text-gray-300 dark:text-gray-600">
                                … et {(schoolData[section.countKey] as unknown[]).length - 5} de plus
                              </li>
                            )}
                          </ul>
                        )}
                    </div>
                  ) : (
                    <p className="italic">Pas encore configuré — utilisez le chat</p>
                  )}
                </div>
              )}
            </div>
          );
        })}

        {/* Assignments count (separate from sections) */}
        {assignments.length > 0 && (
          <div className="mt-3 px-3 py-2 text-[12px] text-gray-400 dark:text-gray-500 border-t border-gray-100 dark:border-gray-800">
            ✓ {assignments.length} affectations enseignant–classe
          </div>
        )}
      </div>
    </div>
  );
}
