'use client';

import { useState, useRef, useEffect } from 'react';
import { Send, Paperclip, Bot, Loader2 } from 'lucide-react';
import { useRouter } from 'next/navigation';
import ChatMessage from '@/components/ChatMessage';
import QuickReplies from '@/components/QuickReplies';
import DataPanel from '@/components/DataPanel';
import { useSession } from '@/hooks/useSession';
import { sendChat, uploadFile, mergeData } from '@/lib/api';
import type { ChatMessage as ChatMessageType, ToolCall } from '@/lib/types';

const WELCOME: ChatMessageType = {
  role: 'ai',
  content:
    'Bienvenue sur TIMEASE ! Je suis votre assistant pour créer l\'emploi du temps. On commence ? Comment s\'appelle votre école ?',
  quickReplies: [
    'Mon école s\'appelle...',
    'Voici mon fichier Excel',
    "J'ai besoin d'aide",
  ],
};

export default function WorkspacePage() {
  const router = useRouter();
  const { sessionId, schoolData, assignments, refreshSession } = useSession();
  const [messages, setMessages] = useState<ChatMessageType[]>([WELCOME]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [pendingToolCalls, setPendingToolCalls] = useState<ToolCall[]>([]);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    setTimeout(() => messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' }), 100);
  };
  
  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  const doSendChat = async (message: string, fileContent?: string) => {
    if (!sessionId) return;
    setIsLoading(true);

    try {
      const result = await sendChat(sessionId, message, fileContent);
      
      const aiResponse: ChatMessageType = {
        role: 'ai',
        content: result.message,
        quickReplies: result.quickReplies,
      };
      
      setMessages((prev) => [...prev, aiResponse]);
      
      if (result.needs_confirmation && result.tool_calls.length > 0) {
        setPendingToolCalls(result.tool_calls);
        setMessages((prev) => [
          ...prev,
          {
            role: 'confirm',
            content: "J'ai extrait ces données, confirmez-vous ?",
            toolCalls: result.tool_calls,
          },
        ]);
      }
      
      refreshSession();
    } catch (error) {
      console.error(error);
      setMessages((prev) => [...prev, { role: 'ai', content: "Une erreur s'est produite lors de la connexion à l'assistant." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const send = () => {
    if (!input.trim() || isLoading) return;
    const msg = input.trim();
    setMessages((prev) => [...prev, { role: 'user', content: msg }]);
    setInput('');
    doSendChat(msg);
  };

  const handleQuickReply = (reply: string) => {
    setMessages((prev) => [...prev, { role: 'user', content: reply }]);
    doSendChat(reply);
  };

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files?.length || !sessionId) return;
    const file = e.target.files[0];
    
    setMessages((prev) => [...prev, { role: 'user', content: `📎 ${file.name}` }]);
    setIsLoading(true);
    
    try {
      const result = await uploadFile(sessionId, file);
      
      if (result.type === 'direct_import') {
        setMessages((prev) => [
          ...prev, 
          { 
            role: 'ai', 
            content: `Fichier importé ! ${result.summary.teachers} enseignants, ${result.summary.classes} classes intégrés avec succès.`,
            quickReplies: ['Continuer la configuration', 'Générer l\'emploi du temps']
          }
        ]);
        refreshSession();
        setIsLoading(false);
      } else if (result.type === 'text_extract') {
        // Background extraction handled by chat flow
        doSendChat(`Analyse ce fichier: ${file.name}`, result.content);
      }
    } catch (error) {
      console.error("Upload error", error);
      setIsLoading(false);
      setMessages((prev) => [...prev, { role: 'ai', content: "Erreur lors de l'importation." }]);
    }
    
    // reset input
    if (fileRef.current) {
      fileRef.current.value = '';
    }
  };

  const handleConfirmClick = async () => {
    if (!sessionId || !pendingToolCalls.length) return;
    setIsLoading(true);
    
    try {
      for (const call of pendingToolCalls) {
        let type = call.name.replace('save_', '');
        if (type === 'school_info') type = 'school_info';
        await mergeData(sessionId, type, call.data);
      }
      
      setMessages((prev) => {
        // Change the last confirm message to regular ai message so buttons vanish
        const updated = [...prev];
        if (updated[updated.length - 1].role === 'confirm') {
          updated[updated.length - 1] = {
            role: 'ai',
            content: "Données confirmées et enregistrées.",
          };
        }
        return updated;
      });
      
      setMessages((prev) => [...prev, { role: 'ai', content: "Données enregistrées ! Que faisons-nous ensuite ?" }]);
      
      refreshSession();
      setPendingToolCalls([]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleRejectClick = () => {
    setPendingToolCalls([]);
    setMessages((prev) => {
      const updated = [...prev];
      if (updated[updated.length - 1].role === 'confirm') {
        updated[updated.length - 1] = {
          role: 'ai',
          content: "Compris, je n'ai rien enregistré.",
        };
      }
      return updated;
    });
    setMessages((prev) => [...prev, { role: 'user', content: "Non, annule." }]);
    setMessages((prev) => [...prev, { role: 'ai', content: "D'accord, corrigez-moi." }]);
  };

  return (
    <div className="flex h-screen">
      {/* ── Chat panel (60%) ───────────────────────────── */}
      <div className="flex-[3] flex flex-col border-r border-gray-100 dark:border-gray-800">
        {/* Header */}
        <div className="flex items-center gap-3 px-6 py-4 border-b border-gray-100 dark:border-gray-800 bg-white/80 dark:bg-gray-950/80 backdrop-blur-sm">
          <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-teal-500 to-emerald-600 flex items-center justify-center text-white">
            <Bot size={16} />
          </div>
          <div>
            <h2 className="text-sm font-semibold text-gray-800 dark:text-gray-200">
              Assistant TIMEASE
            </h2>
            <p className="text-xs text-gray-400">
              {isLoading ? 'En train de réfléchir…' : 'En ligne'}
            </p>
          </div>
        </div>

        {/* Messages */}
        <div className="flex-1 overflow-y-auto px-6 py-4 space-y-4">
          {messages.map((msg, i) => (
            <div key={i}>
              <ChatMessage 
                message={msg} 
                onConfirm={i === messages.length - 1 ? handleConfirmClick : undefined}
                onReject={i === messages.length - 1 ? handleRejectClick : undefined}
              />
              {msg.quickReplies && msg.quickReplies.length > 0 && i === messages.length - 1 && !isLoading && (
                <div className={`${msg.role === 'user' ? 'flex justify-end' : 'ml-11'}`}>
                  <QuickReplies replies={msg.quickReplies} onSelect={handleQuickReply} />
                </div>
              )}
            </div>
          ))}

          {/* Typing indicator */}
          {isLoading && (
            <div className="flex gap-3 animate-in">
              <div className="w-8 h-8 rounded-full bg-gradient-to-br from-teal-500 to-emerald-600 flex items-center justify-center text-white shrink-0">
                <Bot size={14} />
              </div>
              <div className="bg-white dark:bg-gray-900 border border-gray-100 dark:border-gray-800 rounded-2xl rounded-tl-md px-4 py-3 shadow-sm flex gap-1.5 items-center">
                <span className="typing-dot w-2 h-2 rounded-full bg-gray-400" />
                <span className="typing-dot w-2 h-2 rounded-full bg-gray-400" />
                <span className="typing-dot w-2 h-2 rounded-full bg-gray-400" />
              </div>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>

        {/* Input bar */}
        <div className="flex items-center gap-2 px-4 py-3 border-t border-gray-200 dark:border-gray-800">
          <button onClick={() => fileRef.current?.click()}>
            <Paperclip size={18} className="text-gray-400 hover:text-teal-600 transition-colors" />
          </button>
          <input type="file" ref={fileRef} className="hidden" accept=".xlsx,.csv,.docx,.txt" onChange={handleUpload} />
          
          <input 
            value={input} 
            onChange={e => setInput(e.target.value)} 
            onKeyDown={e => e.key === 'Enter' && send()}
            placeholder="Décrivez votre école ou envoyez un fichier..."
            className="flex-1 px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 text-sm focus:outline-none focus:ring-2 focus:ring-teal-500 placeholder:text-gray-400" 
            disabled={isLoading}
          />
          
          <button onClick={send} disabled={isLoading || !input.trim()}
            className="p-2 rounded-lg bg-teal-600 text-white hover:bg-teal-700 disabled:opacity-50 transition-colors">
            {isLoading ? <Loader2 size={16} className="animate-spin" /> : <Send size={16} />}
          </button>
        </div>
      </div>

      {/* ── Data panel (40%) ──────────────────────────── */}
      <div className="flex-[2] bg-white dark:bg-gray-950 overflow-hidden">
        <DataPanel
          schoolData={schoolData as Record<string, unknown>}
          assignments={assignments as Record<string, unknown>[]}
          sessionId={sessionId}
        />
      </div>
    </div>
  );
}
